import Footer from "@/components/Footer";
import { LangAndTheme } from "@/components/RightContent";
import { appTitle, fallbackEnUs, t } from "@/global";
import { LoginForm, ProFormCaptcha, ProFormText } from "@ant-design/pro-form";
import { Button, Form, message, theme } from "antd";
const { useToken } = theme;
import styles from './../Login/index.less';
import { LockOutlined, MailOutlined } from "@ant-design/icons";
import { FormattedMessage, useIntl, history } from "@umijs/max";
import { getLoginVerificationCode, resetPassword } from "@/services/api";
import type { API } from "@/services/typings";
import { UserPassword } from "@/pages/UserList";
import { useState } from "react";

function trimEmailForVerification(email?: string): string {
  return (email ?? '').trim();
}

const ResetPassword: React.FC = () => {
  const { token } = useToken();
  const intl = useIntl();
  const [form] = Form.useForm();
  const [logging, setLogging] = useState<boolean>(false);
  const [secret, setSecret] = useState<string>();

  const handleSubmit = async (values: Partial<API.ResetPasswordRequest>) => {
    try {
      if (!secret) {
        message.error('Please get verification code first');
        return;
      }
      if (!values.email || !values.password || !values.code) {
        message.error('Please fill in all fields');
        return;
      }
      const email = trimEmailForVerification(values.email);
      await resetPassword({
        email,
        password: values.password,
        code: values.code,
        secret: secret,
      });
      message.success('Password reset successfully');
      history.push('/user/login');
    } catch (e) {
      message.error(typeof e === 'string' ? e : 'Failed to reset password');
    }
  };

  return fallbackEnUs(
    <div className={styles.container} style={{ backgroundColor: token.colorBgContainer }}>
      <LangAndTheme />
      <div className={styles.content}>
        <LoginForm
          form={form}
          logo={<img alt="logo" src="./logo.svg" />}
          title="RustDesk"
          subTitle={t('app.title', true, appTitle as string)}
          onFinish={async (values) => {
            setLogging(true);
            await handleSubmit(values);
            setLogging(false);
          }}
          submitter={{
            render: () => {
              return (
                <>
                  {<Button loading={logging} type="primary" size="large" block htmlType="submit">
                    {t('reset_password')}
                  </Button>}
                  {(
                    <Button
                      style={{ marginTop: '20px' }}
                      size="large"
                      block
                      onClick={() => {
                        history.push('/user/login');
                      }}
                    >
                      {t('Back')}
                    </Button>
                  )}
                </>
              );
            },
            submitButtonProps: {
              size: 'large',
              style: {
                width: '100%',
              },
            },
          }}
        >
          <ProFormText
            fieldProps={{
              size: 'large',
              prefix: <MailOutlined className={styles.prefixIcon} />,
            }}
            name="email"
            placeholder={t('Enter your email address', true) as string}
            rules={[
              {
                required: true,
                whitespace: true,
                message: t('Email is required', true),
              },
              {
                type: 'email',
                transform: (value) => trimEmailForVerification(value),
                message: t('Invalid email format', true),
              },
            ]}
            validateTrigger={['onBlur']}
          />
          <ProFormCaptcha
            fieldProps={{
              size: 'large',
              prefix: <LockOutlined className={styles.prefixIcon} />,
            }}
            captchaProps={{
              size: 'large',
            }}
            placeholder={t('pages.login.captcha.placeholder', true) as string}
            captchaTextRender={(timing, count) => {
              if (timing) {
                return `${count} ${t('pages.getCaptchaSecondText', true, '', intl) as string}`;
              }
              return t('pages.login.phoneLogin.getVerificationCode', true, '', intl) as string;
            }}
            name="code"
            rules={[
              {
                required: true,
                whitespace: true,
                message: <FormattedMessage id="pages.login.captcha.required" />,
              },
            ]}
            phoneName="email"
            onGetCaptcha={async (email) => {
              try {
                const normalizedEmail = trimEmailForVerification(email);
                const { secret } = await getLoginVerificationCode({
                  data: { email: normalizedEmail },
                });
                setSecret(secret);
                message.success(t("If an account exists, a verification code has been sent."));
              } catch (e) {
                message.error(typeof e === 'string' ? (e as string) : t("Failed to get verification code"));
              }
            }}
          />
          <UserPassword required={true} />
        </LoginForm>
        <Footer />
      </div >
    </div>
  );
};

export default ResetPassword;
